What does this program print?

```cpp
#include <iostream>
template <typename T>
class Label {
public:
    static void show() { std::cout << "generic\n"; }
};
template <>
class Label<int> {
public:
    static void show() { std::cout << "integer\n"; }
};
int main() {
    Label<double>::show();
    Label<int>::show();
    Label<char>::show();
}
```

The programmer wants to define `Storage<bool>::print()` outside the class body. This code does not compile. What is the bug?

```cpp
#include <iostream>
template <typename T>
class Storage { T d_; public: void print() const; };
template <typename T>
void Storage<T>::print() const { std::cout << d_ << "\n"; }
template <>
class Storage<bool> { bool d_; public: explicit Storage(bool v): d_{v}{} void print() const; };
template <>   // BUG
void Storage<bool>::print() const { std::cout << (d_? "true":"false") << "\n"; }
```

